+++ b/src-tauri/src/features/iwe/service.rs
@@ -0,0 +1,299 @@
+use std::collections::HashMap;
+use std::path::PathBuf;
+use std::sync::Arc;
+use tauri::{AppHandle, State};
+use tokio::sync::Mutex;
+
+use crate::shared::lsp_client::{LspClient, LspClientConfig, LspClientError};
+use crate::shared::storage;
+use super::types::*;
+
+pub struct IweState {
+    clients: Mutex<HashMap<String, Arc<LspClient>>>,
+}
+
+impl Default for IweState {
+    fn default() -> Self {
+        Self { clients: Mutex::new(HashMap::new()) }
+    }
+}
+
+fn vault_root_uri(app: &AppHandle, vault_id: &str) -> Result<(PathBuf, String), String> {
+    let path = storage::vault_path(app, vault_id)?;
+    let uri = format!("file://{}", path.display());
+    Ok((path, uri))
+}
+
+fn file_uri(vault_path: &PathBuf, file_path: &str) -> String {
+    let abs = vault_path.join(file_path);
+    format!("file://{}", abs.display())
+}
+
+fn uri_to_vault_relative(uri: &str, vault_path: &PathBuf) -> String {
+    let raw = uri.strip_prefix("file://").unwrap_or(uri);
+    if let Ok(rel) = std::path::Path::new(raw).strip_prefix(vault_path) {
+        rel.to_string_lossy().into_owned()
+    } else {
+        raw.to_string()
+    }
+}
+
+fn parse_range(v: &serde_json::Value) -> IweRange {
+    let start = &v["start"];
+    let end = &v["end"];
+    IweRange {
+        start_line: start["line"].as_u64().unwrap_or(0) as u32,
+        start_character: start["character"].as_u64().unwrap_or(0) as u32,
+        end_line: end["line"].as_u64().unwrap_or(0) as u32,
+        end_character: end["character"].as_u64().unwrap_or(0) as u32,
+    }
+}
+
+fn parse_location(v: &serde_json::Value, vault_path: &PathBuf) -> IweLocation {
+    let uri = v["uri"].as_str().unwrap_or("");
+    let rel = uri_to_vault_relative(uri, vault_path);
+    IweLocation { uri: rel, range: parse_range(&v["range"]) }
+}
+
+async fn apply_workspace_edit(
+    edit: &serde_json::Value,
+    vault_path: &PathBuf,
+) -> IweWorkspaceEditResult {
+    let mut result = IweWorkspaceEditResult {
+        files_created: vec![],
+        files_deleted: vec![],
+        files_modified: vec![],
+        errors: vec![],
+    };
+
+    if let Some(changes) = edit["documentChanges"].as_array() {
+        for op in changes {
+            if let Some(kind) = op["kind"].as_str() {
+                match kind {
+                    "create" => {
+                        let uri = op["uri"].as_str().unwrap_or("");
+                        let rel = uri_to_vault_relative(uri, vault_path);
+                        match tokio::fs::write(vault_path.join(&rel), "").await {
+                            Ok(_) => result.files_created.push(rel),
+                            Err(e) => result.errors.push(format!("create {}: {}", rel, e)),
+                        }
+                    }
+                    "rename" => {
+                        let old_uri = op["oldUri"].as_str().unwrap_or("");
+                        let new_uri = op["newUri"].as_str().unwrap_or("");
+                        let old_rel = uri_to_vault_relative(old_uri, vault_path);
+                        let new_rel = uri_to_vault_relative(new_uri, vault_path);
+                        match tokio::fs::rename(vault_path.join(&old_rel), vault_path.join(&new_rel)).await {
+                            Ok(_) => {
+                                result.files_modified.push(old_rel);
+                                result.files_created.push(new_rel);
+                            }
+                            Err(e) => result.errors.push(format!("rename {}: {}", old_rel, e)),
+                        }
+                    }
+                    "delete" => {
+                        let uri = op["uri"].as_str().unwrap_or("");
+                        let rel = uri_to_vault_relative(uri, vault_path);
+                        match tokio::fs::remove_file(vault_path.join(&rel)).await {
+                            Ok(_) => result.files_deleted.push(rel),
+                            Err(e) => result.errors.push(format!("delete {}: {}", rel, e)),
+                        }
+                    }
+                    _ => {}
+                }
+            } else if let Some(edits) = op["edits"].as_array() {
+                let uri = op["textDocument"]["uri"].as_str().unwrap_or("");
+                let rel = uri_to_vault_relative(uri, vault_path);
+                let file_path = vault_path.join(&rel);
+                let content = tokio::fs::read_to_string(&file_path).await.unwrap_or_default();
+                let lines: Vec<&str> = content.lines().collect();
+                let mut new_lines: Vec<String> = lines.iter().map(|l| l.to_string()).collect();
+
+                let mut sorted_edits: Vec<_> = edits.iter().collect();
+                sorted_edits.sort_by(|a, b| {
+                    let al = a["range"]["start"]["line"].as_u64().unwrap_or(0);
+                    let bl = b["range"]["start"]["line"].as_u64().unwrap_or(0);
+                    bl.cmp(&al)
+                });
+
+                for edit in sorted_edits {
+                    let start_line = edit["range"]["start"]["line"].as_u64().unwrap_or(0) as usize;
+                    let start_char = edit["range"]["start"]["character"].as_u64().unwrap_or(0) as usize;
+                    let end_line = edit["range"]["end"]["line"].as_u64().unwrap_or(0) as usize;
+                    let end_char = edit["range"]["end"]["character"].as_u64().unwrap_or(0) as usize;
+                    let new_text = edit["newText"].as_str().unwrap_or("");
+
+                    if start_line == end_line && start_line < new_lines.len() {
+                        let line = &new_lines[start_line];
+                        let before = line.chars().take(start_char).collect::<String>();
+                        let after = line.chars().skip(end_char).collect::<String>();
+                        new_lines[start_line] = format!("{}{}{}", before, new_text, after);
+                    } else if start_line < new_lines.len() {
+                        let before = new_lines[start_line].chars().take(start_char).collect::<String>();
+                        let after = if end_line < new_lines.len() {
+                            new_lines[end_line].chars().skip(end_char).collect::<String>()
+                        } else {
+                            String::new()
+                        };
+                        let replacement = format!("{}{}{}", before, new_text, after);
+                        new_lines.splice(start_line..=end_line.min(new_lines.len() - 1), [replacement]);
+                    }
+                }
+
+                let new_content = new_lines.join("\n");
+                match tokio::fs::write(&file_path, new_content).await {
+                    Ok(_) => result.files_modified.push(rel),
+                    Err(e) => result.errors.push(format!("write {}: {}", rel, e)),
+                }
+            }
+        }
+    }
+
+    result
+}
+
+fn lsp_err(e: LspClientError) -> String { e.to_string() }
+
+#[tauri::command]
+#[specta::specta]
+pub async fn iwe_start(vault_id: String, app: AppHandle, state: State<'_, IweState>) -> Result<(), String> {
+    let (vault_path, root_uri) = vault_root_uri(&app, &vault_id)?;
+    let capabilities = serde_json::json!({
+        "textDocument": {
+            "synchronization": { "dynamicRegistration": false, "didSave": true },
+            "hover": { "dynamicRegistration": false },
+            "references": { "dynamicRegistration": false },
+            "definition": { "dynamicRegistration": false },
+            "rename": { "dynamicRegistration": false },
+            "codeAction": {
+                "dynamicRegistration": false,
+                "resolveSupport": { "properties": ["edit"] }
+            },
+            "completion": { "dynamicRegistration": false },
+            "formatting": { "dynamicRegistration": false },
+            "inlayHint": { "dynamicRegistration": false }
+        },
+        "workspace": {
+            "symbol": { "dynamicRegistration": false },
+            "workspaceEdit": { "documentChanges": true }
+        }
+    });
+    let config = LspClientConfig {
+        binary_path: "iwes".to_string(),
+        args: vec![vault_path.to_string_lossy().into_owned()],
+        root_uri,
+        capabilities,
+    };
+    let client = Arc::new(LspClient::start(config).await.map_err(lsp_err)?);
+    state.clients.lock().await.insert(vault_id, client);
+    Ok(())
+}
+
+#[tauri::command]
+#[specta::specta]
+pub async fn iwe_stop(vault_id: String, state: State<'_, IweState>) -> Result<(), String> {
+    let client = state.clients.lock().await.remove(&vault_id);
+    if let Some(client) = client {
+        if let Ok(inner) = Arc::try_unwrap(client) {
+            inner.stop().await;
+        }
+    }
+    Ok(())
+}
+
+macro_rules! get_client {
+    ($state:expr, $vault_id:expr) => {{
+        let arc = {
+            let guard = $state.clients.lock().await;
+            guard.get($vault_id).cloned()
+        };
+        match arc {
+            Some(c) => c,
+            None => return Err(format!("IWE not started for vault {}", $vault_id)),
+        }
+    }};
+}
