+    let client = get_client!(state, &vault_id);
+    let result = client.send_request("textDocument/hover", params).await.map_err(lsp_err)?;
+    let contents = result["contents"]["value"].as_str().or_else(|| result["contents"].as_str()).map(|s| s.to_string());
+    Ok(IweHoverResult { contents })
