+    let uri = file_uri(&vault_path, &file_path);
+    let params = serde_json::json!({ "textDocument": { "uri": uri }, "position": { "line": line, "character": character } });
+    let client = get_client!(state, &vault_id);
+    let result = client.send_request("textDocument/definition", params).await.map_err(lsp_err)?;
+    if result.is_null() { return Ok(None); }
+    let loc = if result.is_array() {
+        result.as_array().and_then(|arr| arr.first()).map(|v| parse_location(v, &vault_path))
+    } else {
+        Some(parse_location(&result, &vault_path))
+    };
+    Ok(loc)
+}
