+pub async fn iwe_completion(vault_id: String, file_path: String, line: u32, character: u32, app: AppHandle, state: State<'_, IweState>) -> Result<Vec<IweCompletionItem>, String> {
+    let (vault_path, _) = vault_root_uri(&app, &vault_id)?;
+    let uri = file_uri(&vault_path, &file_path);
+    let params = serde_json::json!({ "textDocument": { "uri": uri }, "position": { "line": line, "character": character } });
+    let client = get_client!(state, &vault_id);
+    let result = client.send_request("textDocument/completion", params).await.map_err(lsp_err)?;
+    let items = result.get("items").and_then(|v| v.as_array()).or_else(|| result.as_array());
+    let completions = items.map(|arr| arr.iter().map(|v| IweCompletionItem {
+        label: v["label"].as_str().unwrap_or("").to_string(),
+        detail: v["detail"].as_str().map(|s| s.to_string()),
+        insert_text: v["insertText"].as_str().map(|s| s.to_string()),
+    }).collect()).unwrap_or_default();
+    Ok(completions)
+}
