+pub async fn iwe_formatting(vault_id: String, file_path: String, app: AppHandle, state: State<'_, IweState>) -> Result<Vec<IweTextEdit>, String> {
+    let (vault_path, _) = vault_root_uri(&app, &vault_id)?;
+    let uri = file_uri(&vault_path, &file_path);
+    let params = serde_json::json!({ "textDocument": { "uri": uri }, "options": { "tabSize": 2, "insertSpaces": true } });
+    let client = get_client!(state, &vault_id);
+    let result = client.send_request("textDocument/formatting", params).await.map_err(lsp_err)?;
+    let edits = result.as_array().map(|arr| arr.iter().map(|v| IweTextEdit {
+        range: parse_range(&v["range"]),
+        new_text: v["newText"].as_str().unwrap_or("").to_string(),
+    }).collect()).unwrap_or_default();
+    Ok(edits)
+}
+
+#[tauri::command]
+#[specta::specta]
+pub async fn iwe_inlay_hints(vault_id: String, file_path: String, app: AppHandle, state: State<'_, IweState>) -> Result<Vec<IweInlayHint>, String> {
+    let (vault_path, _) = vault_root_uri(&app, &vault_id)?;
+    let uri = file_uri(&vault_path, &file_path);
+    let content = tokio::fs::read_to_string(vault_path.join(&file_path)).await.unwrap_or_default();
+    let line_count = content.lines().count().max(1) as u32;
+    let params = serde_json::json!({ "textDocument": { "uri": uri }, "range": { "start": { "line": 0, "character": 0 }, "end": { "line": line_count - 1, "character": 0 } } });
+    let client = get_client!(state, &vault_id);
+    let result = client.send_request("textDocument/inlayHint", params).await.map_err(lsp_err)?;
+    let hints = result.as_array().map(|arr| arr.iter().map(|v| IweInlayHint {
+        position_line: v["position"]["line"].as_u64().unwrap_or(0) as u32,
+        position_character: v["position"]["character"].as_u64().unwrap_or(0) as u32,
+        label: v["label"].as_str().unwrap_or("").to_string(),
+    }).collect()).unwrap_or_default();
+    Ok(hints)
+}

