+import type { IwePort } from "../ports";
+import type { IweStore } from "../state/iwe_store.svelte";
+import type { IweCodeAction, IweRange, IweWorkspaceEditResult } from "../types";
+import type { VaultStore } from "$lib/features/vault";
+import type { OpStore } from "$lib/app/orchestration/op_store.svelte";
+
+export class IweService {
+  constructor(
+    private readonly port: IwePort,
+    private readonly store: IweStore,
+    private readonly vault_store: VaultStore,
+    private readonly op_store: OpStore,
+  ) {}
+
+  private get vault_id(): string | null {
+    return this.vault_store.vault?.id ?? null;
+  }
+
+  private set_error(e: unknown) {
+    this.store.set_error(e instanceof Error ? e.message : String(e));
+    this.store.set_status("error");
+  }
+
+  async start() {
+    const vault_id = this.vault_id;
+    if (!vault_id) return;
+    this.store.set_status("starting");
+    try {
+      await this.port.start(vault_id);
+      this.store.set_status("running");
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+
+  async stop() {
+    const vault_id = this.vault_id;
+    if (!vault_id) return;
+    try {
+      await this.port.stop(vault_id);
+      this.store.set_status("stopped");
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+
+  async hover(file_path: string, line: number, character: number) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    try {
+      const result = await this.port.hover(vault_id, file_path, line, character);
+      this.store.set_hover(result);
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+
+  async get_references(file_path: string, line: number, character: number) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    try {
+      const refs = await this.port.references(vault_id, file_path, line, character);
+      this.store.set_references(refs);
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+
+  async get_code_actions(file_path: string, range: IweRange) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    try {
+      const actions = await this.port.code_actions(vault_id, file_path, range.start_line, range.start_character, range.end_line, range.end_character);
+      this.store.set_code_actions(actions);
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+
+  async resolve_code_action(action: IweCodeAction): Promise<IweWorkspaceEditResult | null> {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return null;
+    try {
+      return await this.port.code_action_resolve(vault_id, action);
+    } catch (e) {
+      this.set_error(e);
+      return null;
+    }
+  }
+
+  async get_workspace_symbols(query: string) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    try {
+      const symbols = await this.port.workspace_symbols(vault_id, query);
+      this.store.set_symbols(symbols);
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+
+  async sync_did_open(file_path: string, content: string) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    await this.port.did_open(vault_id, file_path, content).catch(() => {});
+  }
+
+  async sync_did_change(file_path: string, version: number, content: string) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    await this.port.did_change(vault_id, file_path, version, content).catch(() => {});
+  }
+
+  async sync_did_save(file_path: string, content: string) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    await this.port.did_save(vault_id, file_path, content).catch(() => {});
+  }
+
+  async rename(file_path: string, line: number, character: number, new_name: string): Promise<IweWorkspaceEditResult | null> {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return null;
+    try {
+      return await this.port.rename(vault_id, file_path, line, character, new_name);
+    } catch (e) {
+      this.set_error(e);
+      return null;
+    }
+  }
+
+  async prepare_rename(file_path: string, line: number, character: number) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return null;
+    try {
+      return await this.port.prepare_rename(vault_id, file_path, line, character);
+    } catch (e) {
+      this.set_error(e);
+      return null;
+    }
+  }
+
+  async goto_definition(file_path: string, line: number, character: number) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return null;
+    try {
+      return await this.port.definition(vault_id, file_path, line, character);
+    } catch (e) {
+      this.set_error(e);
+      return null;
+    }
+  }
+
+  async get_completions(file_path: string, line: number, character: number) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    try {
+      const items = await this.port.completion(vault_id, file_path, line, character);
+      this.store.set_completions(items);
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+
+  async format_document(file_path: string) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return null;
+    try {
+      return await this.port.formatting(vault_id, file_path);
+    } catch (e) {
+      this.set_error(e);
+      return null;
+    }
+  }
+
+  async get_inlay_hints(file_path: string) {
+    const vault_id = this.vault_id;
+    if (!vault_id || this.store.status !== "running") return;
+    try {
+      const hints = await this.port.inlay_hints(vault_id, file_path);
+      this.store.set_inlay_hints(hints);
+    } catch (e) {
+      this.set_error(e);
+    }
+  }
+}

