+export function register_iwe_actions(
+  registry: ActionRegistry,
+  iwe_service: IweService,
+  iwe_store: IweStore,
+) {
+  registry.register({
+    id: "iwe.start",
+    label: "IWE: Start Language Server",
+    execute: async () => {
+      await iwe_service.start();
+    },
+  });
+
+  registry.register({
+    id: "iwe.stop",
+    label: "IWE: Stop Language Server",
+    execute: async () => {
+      await iwe_service.stop();
+    },
+  });
+
+  registry.register({
+    id: "iwe.hover_at_cursor",
+    label: "IWE: Show Hover Info",
+    execute: async (payload: unknown) => {
+      const p = payload as { file_path: string; line: number; character: number };
+      await iwe_service.hover(p.file_path, p.line, p.character);
+    },
+  });
+
+  registry.register({
+    id: "iwe.show_references",
+    label: "IWE: Show References",
+    execute: async (payload: unknown) => {
+      const p = payload as { file_path: string; line: number; character: number };
+      await iwe_service.get_references(p.file_path, p.line, p.character);
+    },
+  });
+
+  registry.register({
+    id: "iwe.show_code_actions",
+    label: "IWE: Show Code Actions",
+    execute: async (payload: unknown) => {
+      const p = payload as { file_path: string; start_line: number; start_character: number; end_line: number; end_character: number };
+      await iwe_service.get_code_actions(p.file_path, { start_line: p.start_line, start_character: p.start_character, end_line: p.end_line, end_character: p.end_character });
+    },
+  });
+
+  registry.register({
+    id: "iwe.resolve_code_action",
+    label: "IWE: Apply Code Action",
+    execute: async (payload: unknown) => {
+      const action = payload as import("../types").IweCodeAction;
+      await iwe_service.resolve_code_action(action);
+    },
+  });
+
+  registry.register({
+    id: "iwe.search_symbols",
