+    },
+  });
+
+  registry.register({
+    id: "iwe.goto_definition",
+    label: "IWE: Go to Definition",
+    execute: async (payload: unknown) => {
+      const p = payload as { file_path: string; line: number; character: number };
+      await iwe_service.goto_definition(p.file_path, p.line, p.character);
