@@ -0,0 +1,55 @@
+import type { IweService } from "$lib/features/iwe";
+import type { IweStore } from "$lib/features/iwe";
+import type { VaultStore } from "$lib/features/vault";
+import { create_logger } from "$lib/shared/utils/logger";
+
+const log = create_logger("iwe_lifecycle_reactor");
+
+type LifecycleState = {
+  iwe_status: "idle" | "starting" | "running" | "error" | "stopped";
+  auto_restart_count: number;
+};
+
+type LifecycleInput = {
+  vault_open: boolean;
+  iwe_status: "idle" | "starting" | "running" | "error" | "stopped";
+};
+
+type LifecycleDecision = {
+  action: "start" | "stop" | "noop";
+  next_auto_restart_count: number;
+};
+
+export function resolve_lifecycle_decision(
+  state: LifecycleState,
+  input: LifecycleInput,
+): LifecycleDecision {
+  if (input.vault_open && (state.iwe_status === "idle" || state.iwe_status === "stopped")) {
+    return { action: "start", next_auto_restart_count: state.auto_restart_count };
+  }
+
+  if (!input.vault_open && (state.iwe_status === "running" || state.iwe_status === "starting")) {
+    return { action: "stop", next_auto_restart_count: 0 };
+  }
+
+  if (input.vault_open && input.iwe_status === "error" && state.auto_restart_count < 1) {
+    return { action: "start", next_auto_restart_count: state.auto_restart_count + 1 };
+  }
+
+  return { action: "noop", next_auto_restart_count: state.auto_restart_count };
+}
+
+export function create_iwe_lifecycle_reactor(
+  vault_store: VaultStore,
+  iwe_store: IweStore,
+  iwe_service: IweService,
+): () => void {
+  let auto_restart_count = 0;
+
+  return $effect.root(() => {
+    $effect(() => {
+      const vault = vault_store.vault;
+
+      if (!vault) {
+        void iwe_service.stop().catch((e: unknown) => {
+          log.from_error("Failed to stop IWE on vault close", e);
+        });
+        auto_restart_count = 0;
+        return;
+      }
+
+      void iwe_service.start().catch((e: unknown) => {
+        log.from_error("Failed to start IWE for vault", e);
+      });
+
+      return () => {
+        void iwe_service.stop().catch((e: unknown) => {
+          log.from_error("Failed to stop IWE on cleanup", e);
+        });
+      };
+    });
+
+    $effect(() => {
+      const status = iwe_store.status;
+
+      if (status === "error" && vault_store.vault) {
+        if (auto_restart_count < 1) {
+          auto_restart_count += 1;
+          log.warn("IWE crashed, attempting auto-restart");
+          void iwe_service.start().catch((e: unknown) => {
+            log.from_error("Auto-restart failed", e);
+          });
+        } else {
+          log.error("IWE crashed twice, giving up auto-restart");
+        }
+      } else if (status === "running") {
+        auto_restart_count = 0;
+      }
+    });
+  });
+}

