+import type { IweService } from "$lib/features/iwe";
+import type { IweStore } from "$lib/features/iwe";
+import type { EditorStore } from "$lib/features/editor";
+
+type DocSyncState = {
+  last_path: string | null;
+  last_version: number;
+  last_is_dirty: boolean;
+};
+
+type DocSyncInput = {
+  open_note_path: string | null;
+  content: string;
+  is_dirty: boolean;
+  iwe_running: boolean;
+};
+
+type DocSyncDecision = {
+  action: "did_open" | "did_change" | "did_save" | "noop";
+  path: string | null;
+  version: number;
+  content: string;
+  next_state: DocSyncState;
+};
+
+export function resolve_document_sync_decision(
+  state: DocSyncState,
+  input: DocSyncInput,
+): DocSyncDecision {
+  const noop = (next: DocSyncState): DocSyncDecision => ({
+    action: "noop",
+    path: null,
+    version: state.last_version,
+    content: "",
+    next_state: next,
+  });
+
+  if (!input.iwe_running || !input.open_note_path) {
+    return noop({ ...state, last_path: input.open_note_path, last_is_dirty: input.is_dirty });
+  }
+
+  const path_changed = input.open_note_path !== state.last_path;
+
+  if (path_changed) {
+    const next_state: DocSyncState = {
+      last_path: input.open_note_path,
+      last_version: 1,
+      last_is_dirty: input.is_dirty,
+    };
+    return { action: "did_open", path: input.open_note_path, version: 1, content: input.content, next_state };
+  }
+
+  if (input.is_dirty && input.content !== "") {
+    const next_version = state.last_version + 1;
+    const next_state: DocSyncState = { ...state, last_version: next_version, last_is_dirty: true };
+    return { action: "did_change", path: input.open_note_path, version: next_version, content: input.content, next_state };
+  }
+
+  if (!input.is_dirty && state.last_is_dirty) {
+    const next_state: DocSyncState = { ...state, last_is_dirty: false };
+    return { action: "did_save", path: input.open_note_path, version: state.last_version, content: input.content, next_state };
+  }
+
+  return noop({ ...state, last_is_dirty: input.is_dirty });
+}
+
+export function create_iwe_document_sync_reactor(
+  editor_store: EditorStore,
+  iwe_store: IweStore,
+  iwe_service: IweService,
+): () => void {
+  let sync_state: DocSyncState = {
+    last_path: null,
+    last_version: 0,
+    last_is_dirty: false,
+  };
+
+  let debounce_timer: ReturnType<typeof setTimeout> | null = null;
+
+  return $effect.root(() => {
+    $effect(() => {
+      const open_note_path = editor_store.open_note?.path ?? null;
+      const content = editor_store.content ?? "";
+      const is_dirty = editor_store.is_dirty;
+      const iwe_running = iwe_store.status === "running";
+
+      const decision = resolve_document_sync_decision(sync_state, {
+        open_note_path,
+        content,
+        is_dirty,
+        iwe_running,
+      });
+
+      sync_state = decision.next_state;
+
+      if (decision.action === "noop" || !decision.path) return;
+
+      if (decision.action === "did_open") {
+        void iwe_service.sync_did_open(decision.path, decision.content);
+      } else if (decision.action === "did_save") {
+        void iwe_service.sync_did_save(decision.path, decision.content);
+      } else if (decision.action === "did_change") {
+        if (debounce_timer) clearTimeout(debounce_timer);
+        const path = decision.path;
+        const version = decision.version;
+        const content = decision.content;
+        debounce_timer = setTimeout(() => {
+          void iwe_service.sync_did_change(path, version, content);
+        }, 500);
+      }
+    });
+  });
+}

