+import { describe, it, expect } from "vitest";
+import { resolve_lifecycle_decision } from "$lib/reactors/iwe_lifecycle.reactor.svelte";
+
+
+describe("iwe_lifecycle decision logic", () => {
+  it("vault open triggers start", () => {
+    const result = resolve_lifecycle_decision(
+      { iwe_status: "idle", auto_restart_count: 0 },
+      { vault_open: true, iwe_status: "idle" },
+    );
+    expect(result.action).toBe("start");
+  });
+
+  it("vault close triggers stop", () => {
+    const result = resolve_lifecycle_decision(
+      { iwe_status: "running", auto_restart_count: 0 },
+      { vault_open: false, iwe_status: "running" },
+    );
+    expect(result.action).toBe("stop");
+  });
+
+  it("vault switch triggers stop then start (two decisions)", () => {
+    const stop_result = resolve_lifecycle_decision(
+      { iwe_status: "running", auto_restart_count: 0 },
+      { vault_open: false, iwe_status: "running" },
+    );
+    expect(stop_result.action).toBe("stop");
+
+    const start_result = resolve_lifecycle_decision(
+      { iwe_status: "stopped", auto_restart_count: 0 },
+      { vault_open: true, iwe_status: "stopped" },
+    );
+    expect(start_result.action).toBe("start");
+  });
+
+  it("noop when vault unchanged and running", () => {
+    const result = resolve_lifecycle_decision(
+      { iwe_status: "running", auto_restart_count: 0 },
+      { vault_open: true, iwe_status: "running" },
+    );
+    expect(result.action).toBe("noop");
+  });
+
+  it("auto-restart once on unexpected error", () => {
+    const result = resolve_lifecycle_decision(
+      { iwe_status: "running", auto_restart_count: 0 },
+      { vault_open: true, iwe_status: "error" },
+    );
+    expect(result.action).toBe("start");
+    expect(result.next_auto_restart_count).toBe(1);
+  });
+
+  it("set permanent error on second crash (no auto-restart)", () => {
+    const result = resolve_lifecycle_decision(
+      { iwe_status: "error", auto_restart_count: 1 },
+      { vault_open: true, iwe_status: "error" },
+    );
+    expect(result.action).toBe("noop");
+  });
+});
